import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { io, Socket } from 'socket.io-client';

const API_URL = 'http://localhost:3001';

// Define types for the data we get from backend
interface FxRateData {
  rate: number;
  timestamp: string;
}

interface FeeBreakdown {
  amount: number;
  currency: string;
  bdtAmount: number;
  totalFee: number;
  bankFees: number;
  techFee: number;
  receiverGets: number;
  yourProfit: number;
  opsCost: number;
}

function App() {
  const [amount, setAmount] = useState('');
  const [currency, setCurrency] = useState('AED');
  const [receiver, setReceiver] = useState('');
  const [fxRate, setFxRate] = useState<FxRateData | null>(null);
  const [feeBreakdown, setFeeBreakdown] = useState<FeeBreakdown | null>(null);
  const [loading, setLoading] = useState(false);
  const [txId, setTxId] = useState<string | null>(null);
  const [status, setStatus] = useState('');

  // WebSocket connection for real‑time updates
  useEffect(() => {
    const socket: Socket = io(API_URL);
    socket.on('status_update', (data: { transactionId: string; status: string; message: string }) => {
      setStatus(data.message);
      if (data.status === 'completed') {
        alert('✅ Money sent!');
      }
    });
    return () => {
      socket.disconnect();
    };
  }, []);

  // Fetch live exchange rate every 30 seconds
  useEffect(() => {
    fetchFxRate();
    const interval = setInterval(fetchFxRate, 30000);
    return () => clearInterval(interval);
  }, []);

  const fetchFxRate = async () => {
    try {
      const res = await axios.get<{ success: boolean; data: FxRateData }>(`${API_URL}/api/fx/current`);
      setFxRate(res.data.data);
    } catch (err) {
      console.log('Rate fetch failed', err);
    }
  };

  const calculateFees = async () => {
    if (!amount || !receiver) return;
    try {
      const res = await axios.post<FeeBreakdown>(`${API_URL}/api/fees/calculate`, {
        amount: parseFloat(amount),
        currency,
        receiver
      });
      setFeeBreakdown(res.data);
    } catch (err) {
      console.log(err);
    }
  };

  const handleSend = async () => {
    if (!fxRate) {
      setStatus('Exchange rate not available');
      return;
    }
    setLoading(true);
    setStatus('Starting transaction...');
    try {
      const res = await axios.post<{ transactionId: string; status: string }>(`${API_URL}/api/remittance/initiate`, {
        amount: parseFloat(amount),
        currency,
        receiver,
        fxRate: fxRate.rate
      });
      setTxId(res.data.transactionId);
      setStatus('Transaction sent. Waiting...');
    } catch (err: any) {
      setStatus('Error: ' + (err.response?.data?.error || err.message));
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ maxWidth: 600, margin: '50px auto', padding: 20 }}>
      <h1>💸 Send Money to Bangladesh</h1>
      <p>Total fee: 1.70% (0.70% banks, 1.00% tech fee)</p>
      {fxRate && (
        <p><strong>Live Rate:</strong> 1 AED = {fxRate.rate.toFixed(4)} BDT</p>
      )}
      <div>
        <label>Amount:</label>
        <input type="number" value={amount} onChange={e => setAmount(e.target.value)} />
        <select value={currency} onChange={e => setCurrency(e.target.value)}>
          <option value="AED">AED</option>
          <option value="USD">USD</option>
          <option value="SAR">SAR</option>
        </select>
      </div>
      <div>
        <label>Receiver bKash:</label>
        <input type="text" value={receiver} onChange={e => setReceiver(e.target.value)} />
      </div>
      <button onClick={calculateFees}>Calculate Fees</button>
      {feeBreakdown && (
        <div style={{ border: '1px solid #ccc', padding: 15, marginTop: 20 }}>
          <p>Amount: {feeBreakdown.amount} {feeBreakdown.currency}</p>
          <p>Converted: ৳{feeBreakdown.bdtAmount.toFixed(2)}</p>
          <p>Total Fee (1.70%): ৳{feeBreakdown.totalFee.toFixed(2)}</p>
          <p>Bank Fees (0.70%): ৳{feeBreakdown.bankFees.toFixed(2)}</p>
          <p>Tech Fee (1.00%): ৳{feeBreakdown.techFee.toFixed(2)}</p>
          <p><strong>Receiver gets: ৳{feeBreakdown.receiverGets.toFixed(2)}</strong></p>
          <p style={{color:'green'}}>Your profit: ৳{feeBreakdown.yourProfit.toFixed(2)}</p>
        </div>
      )}
      <button onClick={handleSend} disabled={loading || !feeBreakdown}>
        {loading ? 'Sending...' : 'Send Money'}
      </button>
      {status && <p>{status}</p>}
      {txId && <p>Transaction ID: {txId}</p>}
    </div>
  );
}

export default App;
